#include<stdio.h>
#include<stdlib.h>
#include<math.h>
float*W;
float rms(long off,int n){float a=0;for(int i=0;i<n;i++)a+=W[off+i]*W[off+i];return sqrtf((double)a/n);}
float avg(long off,int n){float a=0;for(int i=0;i<n;i++)a+=W[off+i];return a/n;}
int main(int argc,char**argv){
FILE*f=fopen(argv[1],"rb");fseek(f,0,SEEK_END);long sz=ftell(f);fseek(f,0,SEEK_SET);
W=malloc(sz);fread(W,1,sz,f);fclose(f);
/* Check if first block looks like wte or wpe */
/* wte should have different rows per token, wpe should have periodic-ish structure */
printf("RMS of first 768: %.4f\n",rms(0,768));
printf("RMS of second 768: %.4f\n",rms(768,768));
printf("RMS of 100th 768: %.4f\n",rms(768*100,768));
/* wpe: position 0 vs position 1 should be similar in magnitude */
/* wte: token 0 vs token 1 could be very different */
/* Check position 1023 (last wpe if wpe first) */
printf("RMS at 1023*768: %.4f\n",rms(1023*768,768));
printf("RMS at 1024*768: %.4f\n",rms(1024*768,768));
/* If wpe first, wpe should be smooth across positions */
printf("wpe[0] avg: %.4f, wpe[1] avg: %.4f\n",avg(0,768),avg(768,768));
/* Scan for layer norm gammas: blocks of 768 where avg|v| is near 1.0 */
int found=0;
for(long o=0;o<124439808-768&&found<10;o+=768){
  float a=0;for(int i=0;i<768;i++)a+=fabsf(W[o+i]);a/=768;
  if(a>0.9&&a<1.1){
    printf("LN_gamma at %ld (%.0f*768): avg|v|=%.4f vals:",o,(float)o/768,a);
    for(int i=0;i<4;i++)printf(" %.4f",W[o+i]);printf("\n");found++;
  }
}
/* Also check for biases of size 2304 and 3072 */
/* 2304 bias: small values, often near 0 */
for(long o=0;o<124439808-2304&&found<15;o+=2304){
  float a=0;for(int i=0;i<2304;i++)a+=W[o+i]*W[o+i];a=sqrtf(a/2304);
  if(a>0.01&&a<0.5){
    float v0=W[o],v1=W[o+1],v2=W[o+2];
    if(fabsf(v0)>0.001||fabsf(v1)>0.001){
      printf("bias2304? at %ld: rms=%.4f vals: %.4f %.4f %.4f\n",o,a,v0,v1,v2);
      found++;
    }
  }
}
return 0;}
